export type Post = {
	id: string;
	authorId?: string;
	defaultLocale?: string;
	slug: string;
	title: string;
	content: string;
	excerpt: string;
	image?: string;
	published: boolean;
	status?: "DRAFT" | "PUBLISHED";
	tags: Tag[];
	publishedAt?: Date;
	createdAt: Date;
	updatedAt: Date;
};

export type Tag = {
	id: string;
	slug: string;
	name: string;
	createdAt: Date;
	updatedAt: Date;
};

/**
 * Post with joined postTag relationships from the database
 */
export type PostWithPostTag = Post & {
	postTag?: Array<{ postId: string; tagId: string }>;
};

export interface SerializedPost
	extends Omit<Post, "createdAt" | "updatedAt" | "publishedAt" | "tags"> {
	tags: SerializedTag[];
	publishedAt?: string;
	createdAt: string;
	updatedAt: string;
}

export interface SerializedTag extends Omit<Tag, "createdAt" | "updatedAt"> {
	createdAt: string;
	updatedAt: string;
}

import { z } from "zod";

const dateFields = {
	publishedAt: z.coerce.date().optional(),
	createdAt: z.coerce.date().optional(),
	updatedAt: z.coerce.date().optional(),
};

const coreFields = {
	title: z.string().min(1, "Title is required"),
	content: z.string().min(1, "Content is required"),
	excerpt: z.string().min(1, "Excerpt is required"),
	image: z.string().optional(),
	published: z.boolean().optional().default(false),
	slug: z.string().min(1, "Slug is required"),
	tags: z
		.array(
			z.union([
				z.object({ name: z.string() }),
				z.object({ id: z.string(), name: z.string(), slug: z.string() }),
			]),
		)
		.optional()
		.default([]),
};

export const PostDomainSchema = z.object({
	id: z.string().optional(),
	...coreFields,
	...dateFields,
});

export const createPostSchema = PostDomainSchema.extend({
	slug: PostDomainSchema.shape.slug.optional(),
}).omit({ id: true }); // no id on create

export const updatePostSchema = PostDomainSchema.extend({
	id: z.string(), // required on update
});

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import slug from "slug";

export function slugify(text: string, locale: string = "en"): string {
	return slug(text, { lower: true, locale });
}

export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}

// Simple, dependency-free throttle with cancel/flush helpers
// Behavior: leading and trailing enabled by default
export function throttle<Args extends unknown[]>(
	callback: (...args: Args) => void,
	waitMs: number,
) {
	let timerId: ReturnType<typeof setTimeout> | null = null;
	let lastInvokeTime = 0;
	let trailingArgs: Args | null = null;

	const invoke = (args: Args) => {
		lastInvokeTime = Date.now();
		callback(...args);
	};

	const throttled = (...args: Args) => {
		const now = Date.now();
		const remaining = waitMs - (now - lastInvokeTime);

		// Leading edge
		if (lastInvokeTime === 0) {
			invoke(args);
			return;
		}

		if (remaining <= 0 || remaining > waitMs) {
			if (timerId) {
				clearTimeout(timerId);
				timerId = null;
			}
			invoke(args);
		} else {
			// Schedule trailing edge
			trailingArgs = args;
			if (!timerId) {
				timerId = setTimeout(() => {
					timerId = null;
					if (trailingArgs) {
						invoke(trailingArgs);
						trailingArgs = null;
					}
				}, remaining);
			}
		}
	};

	throttled.cancel = () => {
		if (timerId) {
			clearTimeout(timerId);
			timerId = null;
		}
		trailingArgs = null;
		lastInvokeTime = 0;
	};

	throttled.flush = () => {
		if (timerId && trailingArgs) {
			clearTimeout(timerId);
			timerId = null;
			invoke(trailingArgs);
			trailingArgs = null;
		}
	};

	return throttled as ((...args: Args) => void) & {
		cancel: () => void;
		flush: () => void;
	};
}

export function stripHtml(html: string): string {
	// Remove HTML tags
	let text = html.replace(/<[^>]*>/g, "");

	// Decode common HTML entities
	text = text
		.replace(/&amp;/g, "&")
		.replace(/&lt;/g, "<")
		.replace(/&gt;/g, ">")
		.replace(/&quot;/g, '"')
		.replace(/&#x27;/g, "'")
		.replace(/&#x2F;/g, "/")
		.replace(/&nbsp;/g, " ")
		.replace(/&hellip;/g, "...");

	// Clean up extra whitespace and newlines
	return text.replace(/\s+/g, " ").trim();
}

export function stripMarkdown(markdown: string): string {
	let text = markdown;

	// Remove headers (# ## ### etc.)
	text = text.replace(/^#{1,6}\s+/gm, "");

	// Remove bold and italic (**text**, *text*, __text__, _text_)
	text = text.replace(/\*\*([^*]+)\*\*/g, "$1");
	text = text.replace(/\*([^*]+)\*/g, "$1");
	text = text.replace(/__([^_]+)__/g, "$1");
	text = text.replace(/_([^_]+)_/g, "$1");

	// Remove strikethrough (~~text~~)
	text = text.replace(/~~([^~]+)~~/g, "$1");

	// Remove inline code (`code`)
	text = text.replace(/`([^`]+)`/g, "$1");

	// Remove code blocks (```code```)
	text = text.replace(/```[\s\S]*?```/g, "");

	// Remove links [text](url) -> text
	text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, "$1");

	// Remove images ![alt](url)
	text = text.replace(/!\[([^\]]*)\]\([^)]+\)/g, "$1");

	// Remove blockquotes (> text)
	text = text.replace(/^>\s+/gm, "");

	// Remove horizontal rules (--- or ***)
	text = text.replace(/^[-*]{3,}$/gm, "");

	// Remove list markers (- * + and numbered lists)
	text = text.replace(/^[\s]*[-*+]\s+/gm, "");
	text = text.replace(/^[\s]*\d+\.\s+/gm, "");

	// Clean up extra whitespace and newlines
	return text
		.replace(/\n\s*\n/g, "\n")
		.replace(/\s+/g, " ")
		.trim();
}

import { Button } from "@/components/ui/button";
import {
	FormControl,
	FormDescription,
	FormItem,
	FormLabel,
	FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { usePluginOverrides } from "@btst/stack/context";
import { Loader2, Upload } from "lucide-react";
import { useRef, useState } from "react";
import { toast } from "sonner";
import type { BlogPluginOverrides } from "../../overrides";
import { BLOG_LOCALIZATION } from "../../localization";

export function FeaturedImageField({
	isRequired,
	value,
	onChange,
	setFeaturedImageUploading,
}: {
	isRequired?: boolean;
	value?: string;
	onChange: (value: string) => void;
	setFeaturedImageUploading: (uploading: boolean) => void;
}) {
	const fileInputRef = useRef<HTMLInputElement>(null);
	const [isUploading, setIsUploading] = useState(false);

	const { uploadImage, Image, localization } = usePluginOverrides<
		BlogPluginOverrides,
		Partial<BlogPluginOverrides>
	>("blog", { localization: BLOG_LOCALIZATION });

	const ImageComponent = Image ? Image : DefaultImage;

	const handleImageUpload = async (
		event: React.ChangeEvent<HTMLInputElement>,
	) => {
		const file = event.target.files?.[0];
		if (!file) return;

		if (!file.type.startsWith("image/")) {
			toast.error(localization.BLOG_FORMS_FEATURED_IMAGE_ERROR_NOT_IMAGE);
			return;
		}

		if (file.size > 4 * 1024 * 1024) {
			toast.error(localization.BLOG_FORMS_FEATURED_IMAGE_ERROR_TOO_LARGE);
			return;
		}

		try {
			setIsUploading(true);
			setFeaturedImageUploading(true);
			const url = await uploadImage(file);
			onChange(url);
			toast.success(localization.BLOG_FORMS_FEATURED_IMAGE_TOAST_SUCCESS);
		} catch (error) {
			toast.error(localization.BLOG_FORMS_FEATURED_IMAGE_TOAST_FAILURE);
			console.error("Failed to upload image:", error);
			toast.error(localization.BLOG_FORMS_FEATURED_IMAGE_TOAST_FAILURE);
		} finally {
			setIsUploading(false);
			setFeaturedImageUploading(false);
		}
	};

	return (
		<FormItem className="flex flex-col">
			<FormLabel>
				{localization.BLOG_FORMS_FEATURED_IMAGE_LABEL}
				{isRequired && (
					<span className="text-destructive">
						{" "}
						{localization.BLOG_FORMS_FEATURED_IMAGE_REQUIRED_ASTERISK}
					</span>
				)}
			</FormLabel>
			<FormControl>
				<div className="space-y-2">
					<div className="flex gap-2">
						<Input
							placeholder={
								localization.BLOG_FORMS_FEATURED_IMAGE_INPUT_PLACEHOLDER
							}
							value={value || ""}
							onChange={(e) => onChange(e.target.value)}
							disabled={isUploading}
						/>
						<Button
							type="button"
							variant="outline"
							onClick={() => fileInputRef.current?.click()}
							disabled={isUploading}
						>
							{isUploading ? (
								<>
									<Loader2 className="mr-2 h-4 w-4 animate-spin" />
									{localization.BLOG_FORMS_FEATURED_IMAGE_UPLOADING_BUTTON}
								</>
							) : (
								<>
									<Upload className="mr-2 h-4 w-4" />
									{localization.BLOG_FORMS_FEATURED_IMAGE_UPLOAD_BUTTON}
								</>
							)}
						</Button>
					</div>
					<input
						ref={fileInputRef}
						type="file"
						accept="image/*"
						onChange={handleImageUpload}
						className="hidden"
					/>
					{isUploading && (
						<div className="flex items-center gap-2 text-muted-foreground text-sm">
							<Loader2 className="h-4 w-4 animate-spin" />
							{localization.BLOG_FORMS_FEATURED_IMAGE_UPLOADING_TEXT}
						</div>
					)}
					{value && !isUploading && (
						<div className="relative">
							<ImageComponent
								src={value}
								alt={localization.BLOG_FORMS_FEATURED_IMAGE_PREVIEW_ALT}
								className="h-auto w-full max-w-xs rounded-md border"
								width={400}
								height={400}
							/>
						</div>
					)}
				</div>
			</FormControl>
			<FormDescription />
			<FormMessage />
		</FormItem>
	);
}

function DefaultImage({
	src,
	alt,
	className,
	width,
	height,
}: {
	src: string;
	alt: string;
	className?: string;
	width?: number;
	height?: number;
}) {
	return (
		<img
			src={src}
			alt={alt}
			className={className}
			width={width}
			height={height}
		/>
	);
}

