"use client";
import { usePluginOverrides } from "@btst/stack/context";
import type { BlogPluginOverrides } from "../../overrides";
import { BLOG_LOCALIZATION } from "../../localization";
import { MarkdownEditor, type MarkdownEditorProps } from "./markdown-editor";

type MarkdownEditorWithOverridesProps = Omit<
	MarkdownEditorProps,
	"uploadImage" | "placeholder"
>;

export function MarkdownEditorWithOverrides(
	props: MarkdownEditorWithOverridesProps,
) {
	const { uploadImage, localization } = usePluginOverrides<
		BlogPluginOverrides,
		Partial<BlogPluginOverrides>
	>("blog", {
		localization: BLOG_LOCALIZATION,
	});

	return (
		<MarkdownEditor
			{...props}
			uploadImage={uploadImage}
			placeholder={localization?.BLOG_FORMS_EDITOR_PLACEHOLDER}
		/>
	);
}

"use client";
import { Crepe, CrepeFeature } from "@milkdown/crepe";
import "@milkdown/crepe/theme/common/style.css";
import "./markdown-editor-styles.css";

import { cn, throttle } from "../../../utils";
import { editorViewCtx, parserCtx } from "@milkdown/kit/core";
import { listener, listenerCtx } from "@milkdown/kit/plugin/listener";
import { Slice } from "@milkdown/kit/prose/model";
import { Selection } from "@milkdown/kit/prose/state";
import { useLayoutEffect, useRef, useState } from "react";

export interface MarkdownEditorProps {
	value?: string;
	onChange?: (markdown: string) => void;
	className?: string;
	/** Optional image upload handler. When provided, enables image upload in the editor. */
	uploadImage?: (file: File) => Promise<string>;
	/** Placeholder text shown when the editor is empty. */
	placeholder?: string;
}

export function MarkdownEditor({
	value,
	onChange,
	className,
	uploadImage,
	placeholder = "Write something...",
}: MarkdownEditorProps) {
	const containerRef = useRef<HTMLDivElement | null>(null);
	const crepeRef = useRef<Crepe | null>(null);
	const isReadyRef = useRef(false);
	const [isReady, setIsReady] = useState(false);
	const onChangeRef = useRef<typeof onChange>(onChange);
	const initialValueRef = useRef<string>(value ?? "");
	type ThrottledFn = ((markdown: string) => void) & {
		cancel?: () => void;
		flush?: () => void;
	};
	const throttledOnChangeRef = useRef<ThrottledFn | null>(null);

	onChangeRef.current = onChange;

	useLayoutEffect(() => {
		if (crepeRef.current) return;
		const container = containerRef.current;
		if (!container) return;

		const crepe = new Crepe({
			root: container,
			defaultValue: initialValueRef.current,
			featureConfigs: {
				[CrepeFeature.Placeholder]: {
					text: placeholder,
				},
				...(uploadImage
					? {
							[CrepeFeature.ImageBlock]: {
								onUpload: async (file: File) => {
									const url = await uploadImage(file);
									return url;
								},
							},
						}
					: {}),
			},
		});

		// Prepare throttled onChange once per editor instance
		throttledOnChangeRef.current = throttle((markdown: string) => {
			if (onChangeRef.current) onChangeRef.current(markdown);
		}, 200);

		crepe.editor
			.config((ctx) => {
				ctx.get(listenerCtx).markdownUpdated((_, markdown) => {
					throttledOnChangeRef.current?.(markdown);
				});
			})
			.use(listener);

		crepe.create().then(() => {
			isReadyRef.current = true;
			setIsReady(true);
		});
		crepeRef.current = crepe;

		return () => {
			try {
				isReadyRef.current = false;
				throttledOnChangeRef.current?.cancel?.();
				throttledOnChangeRef.current = null;
				crepe.destroy();
			} finally {
				crepeRef.current = null;
			}
		};
	}, []);

	useLayoutEffect(() => {
		if (!isReady) return;
		if (!crepeRef.current) return;
		if (typeof value !== "string") return;

		let currentMarkdown: string | undefined;
		try {
			currentMarkdown = crepeRef.current?.getMarkdown?.();
		} catch {
			// Editor may not have finished initializing its view/state; skip sync for now
			return;
		}

		if (currentMarkdown === value) return;

		crepeRef.current.editor.action((ctx) => {
			const view = ctx.get(editorViewCtx);
			if (view?.hasFocus?.() === true) return;
			const parser = ctx.get(parserCtx);
			const doc = parser(value);
			if (!doc) return;

			const state = view.state;
			const selection = state.selection;
			const from = selection.from;

			let tr = state.tr;
			tr = tr.replace(0, state.doc.content.size, new Slice(doc.content, 0, 0));

			const docSize = doc.content.size;
			const safeFrom = Math.max(1, Math.min(from, Math.max(1, docSize - 2)));
			tr = tr.setSelection(Selection.near(tr.doc.resolve(safeFrom)));
			view.dispatch(tr);
		});
	}, [value, isReady]);

	return (
		<div ref={containerRef} className={cn("milkdown-custom", className)} />
	);
}

"use client";
import {
	createPostSchema as PostCreateSchema,
	updatePostSchema as PostUpdateSchema,
} from "../../../schemas";

import { Button } from "@/components/ui/button";

import {
	Form,
	FormControl,
	FormDescription,
	FormField,
	FormItem,
	FormLabel,
	FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";

import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import {
	useCreatePost,
	useSuspensePost,
	useUpdatePost,
	useDeletePost,
} from "@btst/stack/plugins/blog/client/hooks";
import { slugify } from "../../../utils";
import {
	AlertDialog,
	AlertDialogAction,
	AlertDialogCancel,
	AlertDialogContent,
	AlertDialogDescription,
	AlertDialogFooter,
	AlertDialogHeader,
	AlertDialogTitle,
	AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2 } from "lucide-react";
import { lazy, memo, Suspense, useEffect, useMemo, useState } from "react";
import {
	type FieldPath,
	type SubmitHandler,
	type UseFormReturn,
	useForm,
} from "react-hook-form";
import { toast } from "sonner";
import { z } from "zod";
import { FeaturedImageField } from "./image-field";

const MarkdownEditor = lazy(() =>
	import("./markdown-editor-with-overrides").then((module) => ({
		default: module.MarkdownEditorWithOverrides,
	})),
);
import { BLOG_LOCALIZATION } from "../../localization";
import { usePluginOverrides } from "@btst/stack/context";
import type { BlogPluginOverrides } from "../../overrides";
import { EmptyList } from "../shared/empty-list";
import { TagsMultiSelect } from "./tags-multiselect";

type CommonPostFormValues = {
	title: string;
	content: string;
	excerpt?: string;
	slug?: string;
	image?: string;
	published?: boolean;
	tags?: Array<{ name: string } | { id: string; name: string; slug: string }>;
};

function PostFormBody<T extends CommonPostFormValues>({
	form,
	onSubmit,
	submitLabel,
	onCancel,
	disabled,
	errorMessage,
	setFeaturedImageUploading,
	initialSlugTouched = false,
}: {
	form: UseFormReturn<T>;
	onSubmit: SubmitHandler<T>;
	submitLabel: string;
	onCancel: () => void;
	disabled: boolean;
	errorMessage?: string;
	setFeaturedImageUploading: (uploading: boolean) => void;
	initialSlugTouched?: boolean;
}) {
	const { localization } = usePluginOverrides<
		BlogPluginOverrides,
		Partial<BlogPluginOverrides>
	>("blog", {
		localization: BLOG_LOCALIZATION,
	});
	const [slugTouched, setSlugTouched] = useState(initialSlugTouched);
	const nameTitle = "title" as FieldPath<T>;
	const nameSlug = "slug" as FieldPath<T>;
	const nameExcerpt = "excerpt" as FieldPath<T>;
	const nameImage = "image" as FieldPath<T>;
	const nameTags = "tags" as FieldPath<T>;
	const nameContent = "content" as FieldPath<T>;
	const namePublished = "published" as FieldPath<T>;
	return (
		<Form {...form}>
			<form className="w-full space-y-4" onSubmit={form.handleSubmit(onSubmit)}>
				{errorMessage && (
					<div className="rounded-md border border-red-200 bg-red-50 p-3 text-red-600 text-sm">
						{errorMessage}
					</div>
				)}

				<FormField
					control={form.control}
					name={nameTitle}
					render={({ field }) => (
						<FormItem>
							<FormLabel>
								{localization.BLOG_FORMS_TITLE_LABEL}
								<span className="text-destructive">
									{localization.BLOG_FORMS_REQUIRED_ASTERISK}
								</span>
							</FormLabel>
							<FormControl>
								<Input
									placeholder={localization.BLOG_FORMS_TITLE_PLACEHOLDER}
									{...field}
									value={String(field.value ?? "")}
									onChange={(e) => {
										const newTitle = e.target.value;
										field.onChange(e);
										// Auto-slugify title if slug is not yet set
										if (!slugTouched) {
											// @ts-expect-error - slugify returns string which is compatible with slug field type
											form.setValue(nameSlug, slugify(newTitle));
										}
									}}
								/>
							</FormControl>
							<FormMessage />
						</FormItem>
					)}
				/>

				<FormField
					control={form.control}
					name={nameSlug}
					render={({ field }) => {
						const currentTitle = form.getValues(nameTitle);
						const autoGeneratedSlug = slugify(String(currentTitle ?? ""));
						const currentSlug = String(field.value ?? "");

						return (
							<FormItem>
								<FormLabel>{localization.BLOG_FORMS_SLUG_LABEL}</FormLabel>
								<FormControl>
									<Input
										placeholder={localization.BLOG_FORMS_SLUG_PLACEHOLDER}
										{...field}
										value={currentSlug}
										onChange={(e) => {
											const newSlug = e.target.value;
											field.onChange(e);
											// Only mark as touched if the user manually edited to something different from auto-generated
											// This allows auto-generation to continue if the slug matches what would be generated
											if (newSlug !== autoGeneratedSlug) {
												setSlugTouched(true);
											}
										}}
									/>
								</FormControl>
								<FormMessage />
							</FormItem>
						);
					}}
				/>

				<FormField
					control={form.control}
					name={nameExcerpt}
					render={({ field }) => (
						<FormItem className="flex flex-col">
							<FormLabel>
								{localization.BLOG_FORMS_EXCERPT_LABEL}
								<span className="text-destructive">
									{localization.BLOG_FORMS_REQUIRED_ASTERISK}
								</span>
							</FormLabel>
							<FormControl>
								<Textarea
									placeholder={localization.BLOG_FORMS_EXCERPT_PLACEHOLDER}
									className="min-h-20"
									value={String(field.value ?? "")}
