const CustomPostCreateSchema = PostCreateSchema.omit({
	createdAt: true,
	updatedAt: true,
	publishedAt: true,
});

const CustomPostUpdateSchema = PostUpdateSchema.omit({
	id: true,
	createdAt: true,
	updatedAt: true,
	publishedAt: true,
});

type AddPostFormProps = {
	onClose: () => void;
	onSuccess: (post: { published: boolean }) => void;
	/** Called once with the form instance so parent components can access form state */
	onFormReady?: (
		form: UseFormReturn<z.input<typeof CustomPostCreateSchema>>,
	) => void;
};

const addPostFormPropsAreEqual = (
	prevProps: AddPostFormProps,
	nextProps: AddPostFormProps,
): boolean => {
	if (prevProps.onClose !== nextProps.onClose) return false;
	if (prevProps.onSuccess !== nextProps.onSuccess) return false;
	if (prevProps.onFormReady !== nextProps.onFormReady) return false;
	return true;
};

const AddPostFormComponent = ({
	onClose,
	onSuccess,
	onFormReady,
}: AddPostFormProps) => {
	const [featuredImageUploading, setFeaturedImageUploading] = useState(false);
	const { localization } = usePluginOverrides<
		BlogPluginOverrides,
		Partial<BlogPluginOverrides>
	>("blog", {
		localization: BLOG_LOCALIZATION,
	});

	// const { uploadImage } = useBlogContext()

	const schema = CustomPostCreateSchema;

	const {
		mutateAsync: createPost,
		isPending: isCreatingPost,
		error: createPostError,
	} = useCreatePost();

	type AddPostFormValues = z.input<typeof schema>;
	const onSubmit = async (data: AddPostFormValues) => {
		// Auto-generate slug from title if not provided
		const slug = data.slug || slugify(data.title);

		// Wait for mutation to complete, including refresh
		const createdPost = await createPost({
			title: data.title,
			content: data.content,
			excerpt: data.excerpt ?? "",
			slug,
			published: data.published ?? false,
			publishedAt: data.published ? new Date() : undefined,
			image: data.image,
			tags: data.tags || [],
		});

		toast.success(localization.BLOG_FORMS_TOAST_CREATE_SUCCESS);

		// Navigate only after mutation completes
		onSuccess({ published: createdPost?.published ?? false });
	};

	// For compatibility with resolver types that require certain required fields,
	// cast the generics to the exact inferred input type to avoid mismatch on optional slug
	const form = useForm<z.input<typeof schema>>({
		resolver: zodResolver(schema),
		defaultValues: {
			title: "",
			content: "",
			excerpt: "",
			slug: undefined,
			published: false,
			image: "",
			tags: [],
		},
	});

	// Expose form instance to parent for AI context integration
	useEffect(() => {
		onFormReady?.(form);
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, []);

	return (
		<PostFormBody
			form={form}
			onSubmit={onSubmit}
			submitLabel={
				isCreatingPost
					? localization.BLOG_FORMS_SUBMIT_CREATE_PENDING
					: localization.BLOG_FORMS_SUBMIT_CREATE_IDLE
			}
			onCancel={onClose}
			disabled={isCreatingPost || featuredImageUploading}
			errorMessage={createPostError?.message}
			setFeaturedImageUploading={setFeaturedImageUploading}
		/>
	);
};

export const AddPostForm = memo(AddPostFormComponent, addPostFormPropsAreEqual);

type EditPostFormProps = {
	postSlug: string;
	onClose: () => void;
	onSuccess: (post: { slug: string; published: boolean }) => void;
	onDelete?: () => void;
	/** Called once with the form instance so parent components can access form state */
	onFormReady?: (
		form: UseFormReturn<z.input<typeof CustomPostUpdateSchema>>,
	) => void;
};

const editPostFormPropsAreEqual = (
	prevProps: EditPostFormProps,
	nextProps: EditPostFormProps,
): boolean => {
	if (prevProps.postSlug !== nextProps.postSlug) return false;
	if (prevProps.onClose !== nextProps.onClose) return false;
	if (prevProps.onSuccess !== nextProps.onSuccess) return false;
	if (prevProps.onDelete !== nextProps.onDelete) return false;
	if (prevProps.onFormReady !== nextProps.onFormReady) return false;
	return true;
};

const EditPostFormComponent = ({
	postSlug,
	onClose,
	onSuccess,
	onDelete,
	onFormReady,
}: EditPostFormProps) => {
	const [featuredImageUploading, setFeaturedImageUploading] = useState(false);
	const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
	const { localization } = usePluginOverrides<
		BlogPluginOverrides,
		Partial<BlogPluginOverrides>
	>("blog", {
		localization: BLOG_LOCALIZATION,
	});
	// const { uploadImage } = useBlogContext()

	const { post } = useSuspensePost(postSlug);

	const initialData = useMemo(() => {
		if (!post) return {};
		return {
			title: post.title,
			content: post.content,
			excerpt: post.excerpt,
			slug: post.slug,
			published: post.published,
			image: post.image || "",
			tags: post.tags.map((tag) => ({
				id: tag.id,
				name: tag.name,
				slug: tag.slug,
			})),
		};
	}, [post]);

	const schema = CustomPostUpdateSchema;

	const {
		mutateAsync: updatePost,
		isPending: isUpdatingPost,
		error: updatePostError,
	} = useUpdatePost();

	const { mutateAsync: deletePost, isPending: isDeletingPost } =
		useDeletePost();

	type EditPostFormValues = z.input<typeof schema>;
	const onSubmit = async (data: EditPostFormValues) => {
		// Wait for mutation to complete, including refresh
		const updatedPost = await updatePost({
			id: post!.id,
			data: {
				id: post!.id,
				title: data.title,
				content: data.content,
				excerpt: data.excerpt ?? "",
				slug: data.slug,
				published: data.published ?? false,
				publishedAt:
					data.published && !post?.published
						? new Date()
						: post?.publishedAt
							? new Date(post.publishedAt)
							: undefined,
				image: data.image,
				tags: data.tags || [],
			},
		});

		toast.success(localization.BLOG_FORMS_TOAST_UPDATE_SUCCESS);

		// Navigate only after mutation completes
		onSuccess({
			slug: updatedPost?.slug ?? "",
			published: updatedPost?.published ?? false,
		});
	};

	const handleDelete = async () => {
		if (!post?.id) return;

		await deletePost({ id: post.id });
		toast.success(localization.BLOG_FORMS_TOAST_DELETE_SUCCESS);
		setDeleteDialogOpen(false);

		// Call onDelete callback if provided, otherwise use onClose
		if (onDelete) {
			onDelete();
		} else {
			onClose();
		}
	};

	const form = useForm<z.input<typeof schema>>({
		resolver: zodResolver(schema),
		defaultValues: {
			title: "",
			content: "",
			excerpt: "",
			slug: "",
			published: false,
			image: "",
			tags: [],
		},
		values: initialData as z.input<typeof schema>,
	});

	// Expose form instance to parent for AI context integration
	useEffect(() => {
		onFormReady?.(form);
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, []);

	if (!post) {
		return <EmptyList message={localization.BLOG_PAGE_NOT_FOUND_DESCRIPTION} />;
	}

	return (
		<>
			<PostFormBody
				form={form}
				onSubmit={onSubmit}
				submitLabel={
					isUpdatingPost
						? localization.BLOG_FORMS_SUBMIT_UPDATE_PENDING
						: localization.BLOG_FORMS_SUBMIT_UPDATE_IDLE
				}
				onCancel={onClose}
				disabled={isUpdatingPost || featuredImageUploading}
				errorMessage={updatePostError?.message}
				setFeaturedImageUploading={setFeaturedImageUploading}
				initialSlugTouched={!!post?.slug}
			/>
			<div className="w-full">
				<AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
					<AlertDialogTrigger asChild>
						<Button
							variant="destructive"
							type="button"
							disabled={
								isUpdatingPost || featuredImageUploading || isDeletingPost
							}
							className="mt-4"
						>
							{localization.BLOG_FORMS_DELETE_BUTTON}
						</Button>
					</AlertDialogTrigger>
					<AlertDialogContent>
						<AlertDialogHeader>
							<AlertDialogTitle>
								{localization.BLOG_FORMS_DELETE_DIALOG_TITLE}
							</AlertDialogTitle>
							<AlertDialogDescription>
								{localization.BLOG_FORMS_DELETE_DIALOG_DESCRIPTION}
							</AlertDialogDescription>
						</AlertDialogHeader>
						<AlertDialogFooter>
							<AlertDialogCancel disabled={isDeletingPost}>
								{localization.BLOG_FORMS_DELETE_DIALOG_CANCEL}
							</AlertDialogCancel>
							<AlertDialogAction
								onClick={(e) => {
									e.preventDefault();
									void handleDelete();
								}}
								disabled={isDeletingPost}
							>
								{isDeletingPost
									? localization.BLOG_FORMS_DELETE_PENDING
									: localization.BLOG_FORMS_DELETE_DIALOG_CONFIRM}
							</AlertDialogAction>
						</AlertDialogFooter>
					</AlertDialogContent>
				</AlertDialog>
			</div>
		</>
	);
};

export const EditPostForm = memo(
	EditPostFormComponent,
	editPostFormPropsAreEqual,
);

import MultipleSelector, {
	type Option,
} from "@/components/ui/multi-select";
import { useTags } from "@btst/stack/plugins/blog/client/hooks";
import type { SerializedTag } from "../../../types";

export function TagsMultiSelect({
	value,
	onChange,
	placeholder,
}: {
	value: Array<{ name: string } | { id: string; name: string; slug: string }>;
	onChange: (
		value: Array<{ name: string } | { id: string; name: string; slug: string }>,
	) => void;
	placeholder?: string;
}) {
	const { tags } = useTags();

	const tagMap = new Map<string, SerializedTag>();
	const idToTagMap = new Map<string, SerializedTag>();
	(tags || []).forEach((tag) => {
		tagMap.set(tag.name.toLowerCase(), tag);
		tagMap.set(tag.slug, tag);
		idToTagMap.set(tag.id, tag);
	});

	const options: Option[] = (tags || []).map((tag) => ({
		value: tag.id,
		label: tag.name,
	}));

	const selectedOptions: Option[] = (value || []).map((tag) => {
		if ("id" in tag && tag.id) {
			return {
				value: tag.id,
				label: tag.name,
			};
		}
		const existingTag = tagMap.get(tag.name.toLowerCase());
		return {
			value: existingTag?.id || tag.name,
			label: tag.name,
		};
	});

	const handleChange = (newOptions: Option[]) => {
		const tagObjects = newOptions.map((option) => {
			const existingTag =
				idToTagMap.get(option.value) ||
				Array.from(tagMap.values()).find(
					(tag) => tag.name.toLowerCase() === option.value.toLowerCase(),
				);

			if (existingTag) {
				return {
					id: existingTag.id,
					name: existingTag.name,
					slug: existingTag.slug,
				};
			}

			return { name: option.value };
		});
		onChange(tagObjects);
	};

	return (
		<MultipleSelector
			value={selectedOptions}
			onChange={handleChange}
			placeholder={placeholder ?? "Search or create tags..."}
			options={options}
			creatable={true}
			hidePlaceholderWhenSelected={true}
			className="w-full"
		/>
	);
}

